import{c as e,Q as a,j as o,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Which Economic Tasks are Performed with AI? Evidence from Millions of Claude Conversations","description":"","frontmatter":{"title":"Which Economic Tasks are Performed with AI? Evidence from Millions of Claude Conversations","authors":"Kunal Handa, Alex Tamkin, Miles McCain, Saffron Huang, Esin Durmus, et al.","published":"2025-03-07T00:00:00.000Z","source":"https://arxiv.org/abs/2503.04761"},"headers":[],"relativePath":"research/papers/2025-03-07-which-economic-tasks-ai-claude-conversations-2503-04761.md","filePath":"research/papers/2025-03-07-which-economic-tasks-ai-claude-conversations-2503-04761.md","lastUpdated":1779901665000}'),r={name:"research/papers/2025-03-07-which-economic-tasks-ai-claude-conversations-2503-04761.md"};function n(s,t,d,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="which-economic-tasks-are-performed-with-ai-evidence-from-millions-of-claude-conversations" tabindex="-1">Which Economic Tasks are Performed with AI? Evidence from Millions of Claude Conversations <a class="header-anchor" href="#which-economic-tasks-are-performed-with-ai-evidence-from-millions-of-claude-conversations" aria-label="Permalink to &quot;Which Economic Tasks are Performed with AI? Evidence from Millions of Claude Conversations&quot;">​</a></h1><p><strong>Authors</strong>: Kunal Handa, Alex Tamkin, Miles McCain, Saffron Huang, Esin Durmus, Sarah Heck, Jared Mueller, Jerry Hong, Stuart Ritchie, Tim Belonax, Kevin K. Troy, Dario Amodei, Jared Kaplan, Jack Clark, Deep Ganguli (all Anthropic) <strong>Submitted</strong>: February 11, 2025 (appeared on arxiv March 2025) <strong>Source</strong>: <a href="https://arxiv.org/abs/2503.04761" target="_blank" rel="noreferrer">https://arxiv.org/abs/2503.04761</a><strong>arXiv ID</strong>: 2503.04761 <strong>Data period</strong>: December 2024 – January 2025</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>First large-scale empirical analysis of how AI systems are actually used across economic tasks, using privacy-preserving Clio analysis of 4+ million Claude.ai conversations mapped to the U.S. Department of Labor&#39;s O*NET Database. AI usage concentrates in software development and writing (~50% combined). Approximately 36% of occupations use AI for at least 25% of their tasks. 57% of usage is augmentative; 43% automative.</p><hr><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><p><strong>Dataset</strong>: 1 million Claude.ai Free/Pro conversations (December 2024 – January 2025) <strong>Mapping tool</strong>: Clio (privacy-preserving) → O<em>NET Database (~20,000 task statements) <strong>Hierarchy</strong>: 3 levels — 12 top-level / 474 middle-level / 19,530 O</em>NET base tasks</p><h3 id="classification-accuracy-human-validation-150-examples" tabindex="-1">Classification accuracy (human validation, 150 examples) <a class="header-anchor" href="#classification-accuracy-human-validation-150-examples" aria-label="Permalink to &quot;Classification accuracy (human validation, 150 examples)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>Accuracy</th></tr></thead><tbody><tr><td>Top level</td><td>95.3%</td></tr><tr><td>Middle level</td><td>91.3%</td></tr><tr><td>O*NET base level</td><td>86.0%</td></tr></tbody></table><hr><h2 id="task-concentration" tabindex="-1">Task Concentration <a class="header-anchor" href="#task-concentration" aria-label="Permalink to &quot;Task Concentration&quot;">​</a></h2><h3 id="top-level-distribution" tabindex="-1">Top-Level Distribution <a class="header-anchor" href="#top-level-distribution" aria-label="Permalink to &quot;Top-Level Distribution&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Share of AI Usage</th></tr></thead><tbody><tr><td>Computer and Mathematical</td><td><strong>37.2%</strong></td></tr><tr><td>Arts, Design, Entertainment, Media</td><td>10.3%</td></tr><tr><td>Education</td><td>significant</td></tr><tr><td>Business/Finance</td><td>significant</td></tr><tr><td>Physical labor occupations</td><td>minimal</td></tr></tbody></table><h3 id="middle-level-tasks-most-common" tabindex="-1">Middle-Level Tasks (most common) <a class="header-anchor" href="#middle-level-tasks-most-common" aria-label="Permalink to &quot;Middle-Level Tasks (most common)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Share</th></tr></thead><tbody><tr><td>Software development &amp; website maintenance</td><td>~14%</td></tr><tr><td>Computer systems programming &amp; debugging</td><td>~11%</td></tr><tr><td>System administration, hardware/software troubleshooting</td><td>4–6%</td></tr><tr><td>Marketing/promotional strategies</td><td>~2–3%</td></tr><tr><td>Data science &amp; ML applications</td><td>~2%</td></tr></tbody></table><hr><h2 id="depth-of-ai-use-within-occupations" tabindex="-1">Depth of AI Use Within Occupations <a class="header-anchor" href="#depth-of-ai-use-within-occupations" aria-label="Permalink to &quot;Depth of AI Use Within Occupations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Threshold (tasks with AI usage)</th><th>% of Occupations</th></tr></thead><tbody><tr><td>At least 75% of tasks</td><td><strong>4%</strong></td></tr><tr><td>At least 50% of tasks</td><td>11%</td></tr><tr><td>At least 25% of tasks</td><td><strong>36%</strong></td></tr><tr><td>At least 10% of tasks</td><td>~57%</td></tr></tbody></table><p><strong>Key finding</strong>: Deep AI integration (&gt;75% task coverage) is rare. AI primarily assists specific tasks within occupations, not wholesale job automation.</p><hr><h2 id="skills-distribution" tabindex="-1">Skills Distribution <a class="header-anchor" href="#skills-distribution" aria-label="Permalink to &quot;Skills Distribution&quot;">​</a></h2><h3 id="highest-ai-presence" tabindex="-1">Highest AI presence <a class="header-anchor" href="#highest-ai-presence" aria-label="Permalink to &quot;Highest AI presence&quot;">​</a></h3><p>Critical Thinking, Reading Comprehension, Programming, Writing</p><h3 id="lowest-ai-presence" tabindex="-1">Lowest AI presence <a class="header-anchor" href="#lowest-ai-presence" aria-label="Permalink to &quot;Lowest AI presence&quot;">​</a></h3><p>Installation, Equipment Maintenance, Repairing (physical interaction skills)</p><hr><h2 id="usage-by-wage-barrier-to-entry" tabindex="-1">Usage by Wage &amp; Barrier to Entry <a class="header-anchor" href="#usage-by-wage-barrier-to-entry" aria-label="Permalink to &quot;Usage by Wage &amp; Barrier to Entry&quot;">​</a></h2><p><strong>Wage</strong>: Peaks in upper wage quartile (Computer Programmers, Web Developers). Drops off at both extremes — waiters and anesthesiologists both show low usage.</p><p><strong>Job Zone (preparation required)</strong>:</p><ul><li>Zone 1–3 (little/medium prep): Lower AI usage</li><li><strong>Zone 4 (considerable prep / bachelor&#39;s degree): Peak usage</strong></li><li>Zone 5 (extensive prep / advanced degrees): Falls below Zone 4</li></ul><p>Human barriers to entry may be significantly different from barriers for language models.</p><hr><h2 id="automation-vs-augmentation" tabindex="-1">Automation vs. Augmentation <a class="header-anchor" href="#automation-vs-augmentation" aria-label="Permalink to &quot;Automation vs. Augmentation&quot;">​</a></h2><p>57% augmentative, 43% automative split across all conversations.</p><h3 id="five-collaboration-patterns" tabindex="-1">Five Collaboration Patterns <a class="header-anchor" href="#five-collaboration-patterns" aria-label="Permalink to &quot;Five Collaboration Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pattern</th><th>Type</th><th>%</th><th>Characteristics</th></tr></thead><tbody><tr><td>Directive</td><td>Automative</td><td>—</td><td>Complete task delegation, minimal interaction (e.g., &quot;Format this doc in Markdown&quot;)</td></tr><tr><td>Feedback Loop</td><td>Automative</td><td>—</td><td>Task completion guided by iterative error feedback (e.g., debugging)</td></tr><tr><td>Task Iteration</td><td>Augmentative</td><td>—</td><td>Collaborative refinement (e.g., draft → refine marketing strategy)</td></tr><tr><td>Learning</td><td>Augmentative</td><td>—</td><td>Knowledge acquisition (e.g., &quot;Explain how neural networks work&quot;)</td></tr><tr><td>Validation</td><td>Augmentative</td><td>smallest</td><td>Work verification (e.g., checking SQL logic)</td></tr></tbody></table><h3 id="automation-heavy-tasks-writing-content-generation-schoolwork-coding-debugging" tabindex="-1">Automation-heavy tasks: writing, content generation, schoolwork, coding/debugging <a class="header-anchor" href="#automation-heavy-tasks-writing-content-generation-schoolwork-coding-debugging" aria-label="Permalink to &quot;Automation-heavy tasks: writing, content generation, schoolwork, coding/debugging&quot;">​</a></h3><h3 id="augmentation-heavy-tasks-front-end-development-professional-communication-general-education" tabindex="-1">Augmentation-heavy tasks: front-end development, professional communication, general education <a class="header-anchor" href="#augmentation-heavy-tasks-front-end-development-professional-communication-general-education" aria-label="Permalink to &quot;Augmentation-heavy tasks: front-end development, professional communication, general education&quot;">​</a></h3><hr><h2 id="model-specialization-claude-3-opus-vs-claude-3-5-sonnet" tabindex="-1">Model Specialization (Claude 3 Opus vs Claude 3.5 Sonnet) <a class="header-anchor" href="#model-specialization-claude-3-opus-vs-claude-3-5-sonnet" aria-label="Permalink to &quot;Model Specialization (Claude 3 Opus vs Claude 3.5 Sonnet)&quot;">​</a></h2><p>Dataset: ~54% Sonnet (new), ~46% Opus</p><table tabindex="0"><thead><tr><th>Model</th><th>Usage Profile</th></tr></thead><tbody><tr><td>Claude 3 Opus</td><td>Higher for creative/educational work — reflects unique character/writing style</td></tr><tr><td>Claude 3.5 Sonnet (new)</td><td>Preferred for coding/software development — reflects stronger coding abilities</td></tr></tbody></table><hr><h2 id="comparison-to-predictive-studies" tabindex="-1">Comparison to Predictive Studies <a class="header-anchor" href="#comparison-to-predictive-studies" aria-label="Permalink to &quot;Comparison to Predictive Studies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Study</th><th>Prediction</th><th>Actual Finding</th></tr></thead><tbody><tr><td>Webb (2019)</td><td>Highest AI exposure at 90th wage percentile</td><td>Actual peak at mid-to-high wage (upper quartile, not top)</td></tr><tr><td>Eloundou et al. (2023)</td><td>80% of workers could have 10%+ tasks affected</td><td><strong>Actual: ~57%</strong> of occupations using AI for 10%+ tasks</td></tr><tr><td>Eloundou et al. (2023)</td><td>Higher healthcare usage predicted</td><td>Healthcare usage not yet materialized; scientific usage higher than predicted</td></tr></tbody></table><hr><h2 id="dataset-validation" tabindex="-1">Dataset Validation <a class="header-anchor" href="#dataset-validation" aria-label="Permalink to &quot;Dataset Validation&quot;">​</a></h2><p>Non-work conversations: only <strong>23%</strong> of dataset. Coursework: <strong>5–10%</strong>. The majority of non-work interactions still mapped to occupational tasks (nutrition planning → dietitian tasks; trading strategy → financial analyst tasks).</p><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>Snapshot (Dec 2024–Jan 2025) may not represent longer time windows</li><li>Claude.ai text-only; excludes image/video output modalities</li><li>Model classification introduces noise</li><li>Cannot track what users do with AI outputs (copy-paste rates unknown)</li><li>O*NET is U.S.-centric; misses global occupational categories</li></ul><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>Current AI usage peaks in software development and technical writing. Deep integration (&gt;75% task coverage) affects only ~4% of occupations. The 57/43 augmentation/automation split suggests AI is primarily a collaborative tool, not yet a wholesale job replacer. Empirical tracking frameworks are essential as AI capabilities expand.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>This is the primary empirical data on <strong>how Claude is actually used in practice</strong>. Key calibrations for workspace:</p><ol><li><strong>Software development = 37% of Claude usage</strong>: validates focus on <code>implementer</code>, <code>test-writer</code>, <code>review-hub</code> as primary workflow skills</li><li><strong>Opus preferred for creative/educational; Sonnet for coding</strong>: aligns with <code>sonnet-pilot</code>&#39;s coding-heavy design and <code>opus-pilot</code>&#39;s architecture/creative use cases</li><li><strong>57% augmentative</strong>: <code>autoresearch</code> and <code>research-hub</code> are augmentation tools — consistent with design</li><li><strong>4% deep integration</strong>: AI is not yet replacing whole jobs — workspace skill design (individual task-level) is correct granularity</li><li><strong>36% occupations at 25% task threshold</strong>: broad adoption, but still task-selective — task-level harness design remains correct approach</li></ol>',59)])])}const p=e(r,[["render",n]]);export{g as __pageData,p as default};
